+function buildPlaceholder(property: string, type: GeneratedOption['type'], enumValues?: string[]): string {
+  const normalized = property.replace(/[A-Z]/g, (char) => `-${char.toLowerCase()}`).replace(/_/g, '-');
+  if (enumValues && enumValues.length > 0) {
